#include <bits/stdc++.h>
#define int long long
#define mk make_pair
#define PII pair<int,int>
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a : b)
#define wh while
#define inf 0x3f3f3f3f3f3f3f3f
#define IOS ios::sync_with_stdio(false);cin.tie(0);cout.tie(0);
#define snd second
#define fst first
#define pb push_back
#define CI const int
#define NP namespace
using NP std;
int quickpow(int a,int b)
{
	int ans=1;
	wh(b)
	{
		if(b&1)ans=ans*a;
        a=a*a;
		b>>=1;
	}
	return ans;
}
CI MAXN=1e6+5;
int a[MAXN],t[MAXN<<2],n,m,lz[MAXN<<2],lzz[MAXN<<2];
void pushup(int o)
{
	t[o]=max(t[o*2],t[o*2+1]);
}
void pushdown(int o,int l,int r)
{
	if(lzz[o])
	{
		t[o*2]=0;
		t[o*2+1]=0;
        lz[o*2]=lz[o*2+1]=0;
		lzz[o*2+1]+=lzz[o];
		lzz[o*2]+=lzz[o];
		lzz[o]=0;
	}
	t[o*2]+=lz[o];
	t[o*2+1]+=lz[o];
	lz[o*2+1]+=lz[o];
	lz[o*2]+=lz[o];
	lz[o]=0;
}
void build(int l=1,int r=n,int o=1)
{
	if(l==r)
	{
		t[o]=a[l];
		return;
	}
	int mid=(l+r)/2;
	build(l,mid,o*2);
	build(mid+1,r,o*2+1);
	pushup(o);
}
void upartd(int s,int e,int k,int l=1,int r=n,int o=1)
{
	if(s<=l&&r<=e)
	{
		t[o]+=k;
		lz[o]+=k;
		return;
	}
	int mid=(l+r)/2;
	pushdown(o,l,r);
	if(s<=mid)upartd(s,e,k,l,mid,o*2);
	if(mid+1<=e)upartd(s,e,k,mid+1,r,o*2+1);
	pushup(o);
}
int query(int s,int e,int l=1,int r=n,int o=1)
{
	if(s<=l&&r<=e)
	{
		return t[o];
	}
	int mid=(l+r)/2;
	pushdown(o,l,r);
	int sum=-inf;
	if(s<=mid)sum=max(sum,query(s,e,l,mid,o*2));
	if(mid+1<=e)sum=max(sum,query(s,e,mid+1,r,o*2+1));
	pushup(o);
	return sum;
}
void modi(int s,int e,int k,int l=1,int r=n,int o=1)
{
	if(s<=l&&r<=e)
	{
		t[o]=k;
		lzz[o]=1;
		lz[o]=k;
		return;
	}
	int mid=(l+r)/2;
	pushdown(o,l,r);
	if(s<=mid)modi(s,e,k,l,mid,o*2);
	if(mid+1<=e)modi(s,e,k,mid+1,r,o*2+1);
	pushup(o);
}
signed main(void)
{

    //freopen(".in","r",stdin);
    //freopen(".out","w",stdout);
	IOS
	cin>>n>>m;
	FOR(i,1,n)cin>>a[i];
	build();
	FOR(i,1,m)
	{
		int cmd,l,r;
		cin>>cmd>>l>>r;
		if(cmd==1)
		{
			int k;
			cin>>k;
			modi(l,r,k);
		}
		else if(cmd==2)
		{
			int k;
            cin>>k;
            upartd(l,r,k);
		} 
        else
        {
            cout<<query(l,r)<<'\n';
        }
	}
    return false;
}
